mapper.select:
select m.id, c.college_name, m.major_code, m.major_name, m.study_years, m.status, m.create_time from major m
left join college c on m.college_id = c.id


        and m.college_id = #{collegeId}


        and m.major_name like CONCAT('%', #{majorName}, '%')


        and m.status = #{status}


order by m.create_time desc

SELECT m.id, m.college_id, c.college_name, m.major_code, m.major_name, m.study_years, m.status, m.create_time, m.update_time
FROM class c left join major m on c.major_id = m.id
WHERE c.id = #{classId}
